// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// List all accounts
	// (GET /accounts)
	GetAccounts(ctx context.Context, request GetAccountsRequestObject) (GetAccountsResponseObject, error)
	// List all accounts
	// (GET /admin/accounts)
	GetAdminAccounts(ctx context.Context, request GetAdminAccountsRequestObject) (GetAdminAccountsResponseObject, error)
	// List the transfers ledger
	// (GET /admin/transfers)
	GetAdminTransfers(ctx context.Context, request GetAdminTransfersRequestObject) (GetAdminTransfersResponseObject, error)
	// List all users
	// (GET /admin/users)
	GetAdminUsers(ctx context.Context, request GetAdminUsersRequestObject) (GetAdminUsersResponseObject, error)
	// Issue a password-reset token for a user
	// (POST /admin/users/{id}/password-reset)
	PostAdminUserPasswordReset(ctx context.Context, request PostAdminUserPasswordResetRequestObject) (PostAdminUserPasswordResetResponseObject, error)
	// Clear a user's login lockout
	// (POST /admin/users/{id}/unlock)
	PostAdminUserUnlock(ctx context.Context, request PostAdminUserUnlockRequestObject) (PostAdminUserUnlockResponseObject, error)
	// Log in with username and password
	// (POST /auth/login)
	PostAuthLogin(ctx context.Context, request PostAuthLoginRequestObject) (PostAuthLoginResponseObject, error)
	// Log out of the current session
	// (POST /auth/logout)
	PostAuthLogout(ctx context.Context, request PostAuthLogoutRequestObject) (PostAuthLogoutResponseObject, error)
	// Return the current authenticated user
	// (GET /auth/me)
	GetAuthMe(ctx context.Context, request GetAuthMeRequestObject) (GetAuthMeResponseObject, error)
	// Change the current user's password
	// (POST /auth/password/change)
	PostAuthPasswordChange(ctx context.Context, request PostAuthPasswordChangeRequestObject) (PostAuthPasswordChangeResponseObject, error)
	// Reset a password using a reset token
	// (POST /auth/password/reset)
	PostAuthPasswordReset(ctx context.Context, request PostAuthPasswordResetRequestObject) (PostAuthPasswordResetResponseObject, error)
	// Request a password-reset token
	// (POST /auth/password/reset-request)
	PostAuthPasswordResetRequest(ctx context.Context, request PostAuthPasswordResetRequestRequestObject) (PostAuthPasswordResetRequestResponseObject, error)
	// Register a new user
	// (POST /auth/register)
	PostAuthRegister(ctx context.Context, request PostAuthRegisterRequestObject) (PostAuthRegisterResponseObject, error)
	// Delay the response by a given number of seconds
	// (GET /delay/{seconds})
	GetDelay(ctx context.Context, request GetDelayRequestObject) (GetDelayResponseObject, error)
	// Echo the incoming request
	// (DELETE /echo)
	DeleteEcho(ctx context.Context, request DeleteEchoRequestObject) (DeleteEchoResponseObject, error)
	// Echo the incoming request
	// (GET /echo)
	GetEcho(ctx context.Context, request GetEchoRequestObject) (GetEchoResponseObject, error)
	// Echo the incoming request
	// (PATCH /echo)
	PatchEcho(ctx context.Context, request PatchEchoRequestObject) (PatchEchoResponseObject, error)
	// Echo the incoming request
	// (POST /echo)
	PostEcho(ctx context.Context, request PostEchoRequestObject) (PostEchoResponseObject, error)
	// Echo the incoming request
	// (PUT /echo)
	PutEcho(ctx context.Context, request PutEchoRequestObject) (PutEchoResponseObject, error)
	// Echo the request headers
	// (GET /headers)
	GetHeaders(ctx context.Context, request GetHeadersRequestObject) (GetHeadersResponseObject, error)
	// Return the caller's IP address
	// (GET /ip)
	GetIp(ctx context.Context, request GetIpRequestObject) (GetIpResponseObject, error)
	// Liveness probe
	// (GET /livez)
	GetLivez(ctx context.Context, request GetLivezRequestObject) (GetLivezResponseObject, error)
	// Probe the per-IP rate limiter
	// (GET /ratelimit)
	GetRatelimit(ctx context.Context, request GetRatelimitRequestObject) (GetRatelimitResponseObject, error)
	// Readiness probe
	// (GET /readyz)
	GetReadyz(ctx context.Context, request GetReadyzRequestObject) (GetReadyzResponseObject, error)
	// Return the request scheme
	// (GET /scheme)
	GetScheme(ctx context.Context, request GetSchemeRequestObject) (GetSchemeResponseObject, error)
	// Startup probe
	// (GET /startupz)
	GetStartupz(ctx context.Context, request GetStartupzRequestObject) (GetStartupzResponseObject, error)
	// Return a given HTTP status code
	// (GET /status/{code})
	GetStatus(ctx context.Context, request GetStatusRequestObject) (GetStatusResponseObject, error)
	// Transfer funds between two accounts
	// (POST /transfer)
	PostTransfer(ctx context.Context, request PostTransferRequestObject) (PostTransferResponseObject, error)
	// Echo the User-Agent header
	// (GET /user-agent)
	GetUserAgent(ctx context.Context, request GetUserAgentRequestObject) (GetUserAgentResponseObject, error)
	// Generate a random UUID
	// (GET /uuid)
	GetUuid(ctx context.Context, request GetUuidRequestObject) (GetUuidResponseObject, error)
	// Build and version metadata
	// (GET /version)
	GetVersion(ctx context.Context, request GetVersionRequestObject) (GetVersionResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

